-- calc_employees_name
-- Field: Employees.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_employees_name(p_employee_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(first_name, '') FROM employees WHERE employee_id = p_employee_id), ' ', (SELECT NULLIF(last_name, '') FROM employees WHERE employee_id = p_employee_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_expense_reports_employee_name
-- Field: ExpenseReports.EmployeeName
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Name from related Employees

CREATE OR REPLACE FUNCTION calc_expense_reports_employee_name(p_expense_report_id TEXT)
RETURNS TEXT AS $$
  SELECT calc_employees_name((SELECT employee FROM expense_reports WHERE expense_report_id = p_expense_report_id));
$$ LANGUAGE sql STABLE;

-- calc_expense_reports_employee_budget_limit
-- Field: ExpenseReports.EmployeeBudgetLimit
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: BudgetLimit from related Employees

CREATE OR REPLACE FUNCTION calc_expense_reports_employee_budget_limit(p_expense_report_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (SELECT budget_limit::numeric FROM employees WHERE employee_id = (SELECT employee FROM expense_reports WHERE expense_report_id = p_expense_report_id));
$$ LANGUAGE sql STABLE;

