-- calc_expense_reports_total_amount
-- Field: ExpenseReports.TotalAmount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_expense_reports_total_amount(p_expense_report_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((amount)::numeric), 0) FROM expense_items WHERE expense_report = p_expense_report_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_expense_reports_is_over_budget
-- Field: ExpenseReports.IsOverBudget
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_expense_reports_is_over_budget(p_expense_report_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN ((calc_expense_reports_employee_budget_limit(p_expense_report_id))::NUMERIC > 0 AND calc_expense_reports_total_amount(p_expense_report_id) > calc_expense_reports_employee_budget_limit(p_expense_report_id)) THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_expense_reports_is_approved
-- Field: ExpenseReports.IsApproved
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_expense_reports_is_approved(p_expense_report_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT NULLIF(approval_status, '') FROM expense_reports WHERE expense_report_id = p_expense_report_id) = 'approved' THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_expense_reports_requires_escalation
-- Field: ExpenseReports.RequiresEscalation
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_expense_reports_requires_escalation(p_expense_report_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (calc_expense_reports_is_over_budget(p_expense_report_id) = TRUE AND calc_expense_reports_is_approved(p_expense_report_id) = FALSE) THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

